return-response.set-body:
@{
                var body = context.Request.Body.As(preserveContent: true) ?? new JObject();
                body["client_id"] = "{{McpClaudeClientId}}";
                body["client_id_issued_at"] = (long)(DateTime.UtcNow - new DateTime(1970, 1, 1)).TotalSeconds;
                if (!body.ContainsKey("scope"))
                {
                    body["scope"] = "{{McpScope}} offline_access";
                }
                return body.ToString();
            }
